 29→	}
 30→
 31→	visibleHeight := (height - 2) / 4
 32→	if visibleHeight < 1 {
 33→		visibleHeight = 1
 34→	}
 35→
 36→	start := 0
 37→	if cursor >= visibleHeight {
 38→		start = cursor - visibleHeight + 1
 39→	}
 40→	end := start + visibleHeight
 41→	if end > len(filtered) {
 42→		end = len(filtered)
 43→	}
 44→
 45→	contentWidth := width - 4
 46→	if contentWidth < 40 {
 47→		contentWidth = 40
 48→	}
 49→
 50→	for i := start; i < end; i++ {
 51→		s := filtered[i]
 52→		block := renderCheckpointBlock(s, contentWidth)
 53→
 54→		if i == cursor {
 55→			sb.WriteString(selectedRowStyle.Width(contentWidth - 2).Render(block))
 56→		} else {
 57→			sb.WriteString(normalRowStyle.Width(contentWidth).Render(block))
 58→		}
 59→		sb.WriteString("\n")
 60→	}
 61→
 62→	if len(filtered) > visibleHeight {
 63→		sb.WriteString(scrollIndicatorStyle.Render(fmt.Sprintf("  (%d/%d)", cursor+1, len(filtered))))
 64→	}
 65→
 66→	return sb.String()
 67→}
 68→
 69→func renderCheckpointBlock(s checkpoint.CheckpointSummary, width int) string {
 70→	sep := dimStyle.Render("  ·  ")
 71→
 72→	title := s.CommitMessage
 73→	if title == "" {
 74→		title = cleanPromptExcerpt(s.Prompt)
 75→	}
 76→	if title == "" {
 77→		title = s.Context
 78→	}
 79→	if title == "" {
 80→		title = s.Branch
 81→	}
 82→	if idx := strings.IndexByte(title, '\n'); idx >= 0 {
 83→		title = title[:idx]
 84→	}
 85→	title = strings.TrimSpace(title)
 86→	if len(title) > width {
 87→		title = title[:width-1] + "…"
 88→	}
 89→	line1 := lipgloss.NewStyle().Bold(true).Render(title)
 90→
 91→	subtitle := ""
 92→	if s.CommitMessage != "" {
 93→		excerpt := cleanPromptExcerpt(s.Prompt)
 94→		if excerpt != "" && excerpt != title {
 95→			if len(excerpt) > width {
 96→				excerpt = excerpt[:width-1] + "…"
 97→			}
 98→			subtitle = dimStyle.Render(excerpt)
 99→		}
100→	}
101→
102→	var leftParts []string
103→	leftParts = append(leftParts, hashStyle.Render(truncateHash(s.ID)))
104→	timeStr := formatTimeAgo(s.CreatedAt)
105→	if timeStr != "" {
106→		leftParts = append(leftParts, dimStyle.Render(timeStr))
107→	}
108→	attribution := formatAttribution(s)
109→	if attribution != "" {
110→		leftParts = append(leftParts, agentBadgeStyle.Render(attribution))
111→	}
112→	leftSide := strings.Join(leftParts, sep)
113→
114→	colDiff := lipgloss.NewStyle().Width(14).Align(lipgloss.Right)
115→	colFiles := lipgloss.NewStyle().Width(10).Align(lipgloss.Right)
116→	colSessions := lipgloss.NewStyle().Width(12).Align(lipgloss.Right)
117→	colTokens := lipgloss.NewStyle().Width(14).Align(lipgloss.Right)
118→
119→	var rightCols []string
120→	if s.Additions > 0 || s.Deletions > 0 {
121→		diffStr := addStyle.Render(fmt.Sprintf("+%d", s.Additions)) + " / " +
122→			delStyle.Render(fmt.Sprintf("-%d", s.Deletions))
123→		rightCols = append(rightCols, colDiff.Render(diffStr))
124→	} else {
125→		rightCols = append(rightCols, colDiff.Render(""))
126→	}
127→	if s.FileCount > 0 {
128→		rightCols = append(rightCols, colFiles.Render(dimStyle.Render(fmt.Sprintf("%d files", s.FileCount))))
129→	} else {
130→		rightCols = append(rightCols, colFiles.Render(""))
131→	}
132→	if s.SessionCount > 0 {
133→		label := "session"
134→		if s.SessionCount > 1 {
135→			label = "sessions"
136→		}
137→		rightCols = append(rightCols, colSessions.Render(dimStyle.Render(fmt.Sprintf("%d %s", s.SessionCount, label))))
138→	} else {
139→		rightCols = append(rightCols, colSessions.Render(""))
140→	}
141→	if s.TotalTokens > 0 {
142→		rightCols = append(rightCols, colTokens.Render(dimStyle.Render(formatTokensShort(s.TotalTokens))))
143→	} else {
144→		rightCols = append(rightCols, colTokens.Render(""))
145→	}
146→	rightSide := strings.Join(rightCols, dimStyle.Render(" · "))
147→
148→	metaLine := leftSide
149→	if rightSide != "" {
150→		padding := width - lipgloss.Width(leftSide) - lipgloss.Width(rightSide)
151→		if padding < 2 {
152→			padding = 2
153→		}
154→		metaLine = leftSide + strings.Repeat(" ", padding) + rightSide
155→	}
156→
157→	if subtitle != "" {
158→		return line1 + "\n" + subtitle + "\n" + metaLine
159→	}
160→	return line1 + "\n" + metaLine
161→}
162→
163→func cleanPromptExcerpt(prompt string) string {
164→	if prompt == "" {
165→		return ""
166→	}
167→
168→	prefixes := []string{
169→		"Implement the following plan:",
170→		"implement the following plan:",
171→	}
172→	cleaned := strings.TrimSpace(prompt)
173→	for _, p := range prefixes {
174→		cleaned = strings.TrimPrefix(cleaned, p)
175→	}
176→	cleaned = strings.TrimSpace(cleaned)
177→
178→	for _, line := range strings.SplitN(cleaned, "\n", 20) {
179→		line = strings.TrimSpace(line)
180→		if line == "" || line == "#" || line == "---" {
181→			continue
182→		}
183→		line = strings.TrimLeft(line, "# ")
184→		line = strings.TrimSpace(line)
185→		if line != "" {
186→			return line
187→		}
188→	}
189→	return ""
190→}
191→
192→func filterSummaries(summaries []checkpoint.CheckpointSummary, filter string) []checkpoint.CheckpointSummary {
193→	if filter == "" {
194→		return summaries
195→	}
196→
197→	f := strings.ToLower(filter)
198→	var result []checkpoint.CheckpointSummary
199→	for i := range summaries {
200→		if strings.Contains(strings.ToLower(summaries[i].Branch), f) ||
201→			strings.Contains(strings.ToLower(summaries[i].Agent), f) ||
202→			strings.Contains(strings.ToLower(summaries[i].Prompt), f) ||
203→			strings.Contains(strings.ToLower(summaries[i].Context), f) ||
204→			strings.Contains(strings.ToLower(summaries[i].ID), f) ||
205→			strings.Contains(strings.ToLower(summaries[i].CommitMessage), f) {
206→			result = append(result, summaries[i])
207→		}
208→	}
209→	return result
210→}
211→
212→func formatTimeAgo(t time.Time) string {
213→	if t.IsZero() {
214→		return ""
215→	}
216→	d := time.Since(t)
217→	switch {
218→	case d < time.Minute:
219→		return "just now"
220→	case d < time.Hour:
221→		m := int(d.Minutes())
222→		return fmt.Sprintf("%dm ago", m)
223→	case d < 24*time.Hour:
224→		h := int(d.Hours())
225→		return fmt.Sprintf("%dh ago", h)
226→	default:
227→		days := int(d.Hours() / 24)
228→		return fmt.Sprintf("%dd ago", days)
229→	}
230→}
231→
232→func formatNumber(n int) string {
233→	if n >= 1000 {
234→		return fmt.Sprintf("%d,%03d", n/1000, n%1000)
235→	}
236→	return fmt.Sprintf("%d", n)
237→}
238→
239→func formatTokensShort(n int) string {
240→	if n >= 1000 {
241→		return fmt.Sprintf("%.1fk tokens", float64(n)/1000)
242→	}
243→	return fmt.Sprintf("%d tokens", n)
244→}
245→
246→func truncate(s string, maxLen int) string {
247→	if len(s) <= maxLen {
248→		return s
249→	}
250→	return s[:maxLen-1] + "…"
251→}
252→
253→func formatAttribution(s checkpoint.CheckpointSummary) string {
254→	agent := truncate(s.Agent, 16)
255→	pct := ""
256→	if s.AgentPercent > 0 {
257→		pct = fmt.Sprintf(" %d%%", s.AgentPercent)
258→	}
259→	if s.Author != "" && agent != "" {
260→		return s.Author + " (" + agent + pct + ")"
261→	}
262→	if s.Author != "" {
263→		return s.Author
