	switch {
	case key.Matches(msg, keys.Confirm):
		action := *m.confirmAction
		m.confirmAction = nil
		return m.runAction(action)

	case key.Matches(msg, keys.Deny), msg.Type == tea.KeyEscape:
		m.confirmAction = nil
		return m, nil
	}

	return m, nil
}

